//   Redirige a /login si el usuario no está autenticado.
//   Redirige según su rol si intenta acceder a una ruta que no le corresponde
//   (ej. usuario normal → /, admin → /admin/productos).
// Flujo principal: App.jsx usa <RequireRole allowedRoles={['admin']}> para la ruta /admin/productos.
// Dónde tocar cambios: ajusta la lógica de fallback si se añaden más roles.
import { Navigate, useLocation } from 'react-router-dom';
import useAuth from '../context/useAuth';

/**
 * Protects routes by authentication and role membership.
 * @param {{ children: React.ReactNode, allowedRoles: Array<string> }} props
 */
export default function RequireRole({ children, allowedRoles }) {
  const { isAuthenticated, user } = useAuth();
  const location = useLocation();

  if (!isAuthenticated) {
    return <Navigate to="/login" replace state={{ from: location }} />;
  }

  const role = String(user?.role || '').toLowerCase();
  const isAllowed = allowedRoles.some((item) => String(item).toLowerCase() === role);

  if (!isAllowed) {
    const fallback = role === 'admin' ? '/admin/productos' : '/';
    return <Navigate to={fallback} replace />;
  }

  return children;
}
